#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        memcpy(B, A, sizeof(A));
        qsort(A, N, sizeof(int), compare);
        int hammingDistance = 0;
        for (int i = 0; i < N; i++) {
            if (A[i] != B[i]) {
                hammingDistance++;
            }
        }
        printf("%d\n", hammingDistance);
        for (int i = 0; i < N; i++) {
            printf("%d ", A[i]);
        }
        printf("\n");
    }
    return 0;
}

